#include "clustering/PlacementHierarchy.h"
#include <cassert>
static int c(PlacementDB&d,const std::string&n,bool f=false){int id=d.addCell(n,1,1,CellType::Standard); d.setCellLocation(n,0,0,f); return id;} int main(){PlacementDB db; int prev=-1; for(int i=0;i<25;i++){int x=c(db,"c"+std::to_string(i)); if(prev>=0){int n=db.addNet("n"+std::to_string(i)); db.addPin(prev,n,0,0,"I"); db.addPin(x,n,0,0,"I");} prev=x;} PlacementHierarchy h; h.build(db,2); assert(h.numLevels()>=2); auto& l=h.level(1); assert(l.stats.target_movable_clusters==5); assert(l.stats.output_movable_clusters<=5 || l.stats.stop_reason!="stopped_by_target"); assert(l.area_conservation_error<=1e-9*25); assert(l.mapping_complete); PlacementHierarchy h2; h2.build(db,2); assert(h.numLevels()==h2.numLevels()); assert(h.level(1).stats.merge_sequence==h2.level(1).stats.merge_sequence);}
